// 1. 并查集（DSU）
class DSU {
private:
    vector<int> parent;
    vector<int> rank;
public:
    DSU(int n) {
        parent.resize(n + 1); // 1-based
        rank.resize(n + 1, 0);
        FOR(i, 1, n) parent[i] = i;
    }

    int find(int x) { // 路径压缩
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    void unite(int x, int y) { // 按秩合并
        x = find(x), y = find(y);
        if (x == y) return;
        if (rank[x] < rank[y]) parent[x] = y;
        else {
            parent[y] = x;
            if (rank[x] == rank[y]) rank[x]++;
        }
    }

    bool is_connected(int x, int y) {
        return find(x) == find(y);
    }
};

// 2. 线段树（单点更新 + 区间查询，支持求和/最大值/最小值）
template <typename T>
class SegmentTree {
private:
    vector<T> tree;
    int n;
    T init_val; // 初始化值（求和=0，最大值=-INF，最小值=INF）
    T (*merge)(T, T); // 合并函数

    void build(int node, int l, int r, const vector<T>& arr) {
        if (l == r) {
            tree[node] = arr[l];
            return;
        }
        int mid = (l + r) / 2;
        build(2 * node, l, mid, arr);
        build(2 * node + 1, mid + 1, r, arr);
        tree[node] = merge(tree[2 * node], tree[2 * node + 1]);
    }

    void update(int node, int l, int r, int pos, T val) {
        if (l == r) {
            tree[node] = val;
            return;
        }
        int mid = (l + r) / 2;
        if (pos <= mid) update(2 * node, l, mid, pos, val);
        else update(2 * node + 1, mid + 1, r, pos, val);
        tree[node] = merge(tree[2 * node], tree[2 * node + 1]);
    }

    T query(int node, int l, int r, int ql, int qr) {
        if (qr < l || ql > r) return init_val;
        if (ql <= l && r <= qr) return tree[node];
        int mid = (l + r) / 2;
        return merge(query(2 * node, l, mid, ql, qr), 
                     query(2 * node + 1, mid + 1, r, ql, qr));
    }

public:
    // 构造函数：arr为1-based数组，merge_func为合并规则，init为初始值
    SegmentTree(const vector<T>& arr, T (*merge_func)(T, T), T init) {
        n = arr.size() - 1;
        init_val = init;
        merge = merge_func;
        tree.resize(4 * (n + 1), init_val);
        build(1, 1, n, arr);
    }

    // 单点更新：pos为位置（1-based），val为新值
    void update(int pos, T val) {
        update(1, 1, n, pos, val);
    }

    // 区间查询：[ql, qr]（1-based）
    T query(int ql, int qr) {
        return query(1, 1, n, ql, qr);
    }

    // 预定义合并函数
    static T sum(T a, T b) { return a + b; }
    static T max_val(T a, T b) { return max(a, b); }
    static T min_val(T a, T b) { return min(a, b); }
};

// 3. 单调栈（找下一个更大元素）
vector<int> next_greater_element(vector<int>& nums) {
    int n = nums.size();
    vector<int> res(n, -1);
    stack<int> st;
    REP(i, n) {
        while (!st.empty() && nums[i] > nums[st.top()]) {
            res[st.top()] = nums[i];
            st.pop();
        }
        st.push(i);
    }
    return res;
}

