// 1. Dijkstra（单源最短路径，正权边）
vector<ll> dijkstra(int start, int n, const vector<vector<pii>>& adj) {
    vector<ll> dist(n + 1, LLINF);
    dist[start] = 0;
    priority_queue<pll, vector<pll>, greater<pll>> pq;
    pq.push({0, start});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u]) continue;
        for (auto [v, w] : adj[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

// ====================== 并查集（Kruskal依赖） ======================
class DSU {
private:
    vector<int> parent;
    vector<int> rank;
public:
    DSU(int n) {
        parent.resize(n + 1); // 1-based
        rank.resize(n + 1, 0);
        for (int i = 1; i <= n; ++i) parent[i] = i;
    }

    int find(int x) { // 路径压缩（递归版）
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    bool unite(int x, int y) { // 按秩合并，返回是否合并成功
        x = find(x), y = find(y);
        if (x == y) return false;
        if (rank[x] < rank[y]) parent[x] = y;
        else {
            parent[y] = x;
            if (rank[x] == rank[y]) rank[x]++;
        }
        return true;
    }

    bool is_connected(int x, int y) {
        return find(x) == find(y);
    }
};

// ====================== Kruskal算法核心 ======================
struct Edge {
    int u, v;    // 边的两个端点（1-based）
    ll w;        // 边的权值（用ll避免溢出）
    // 重载<，用于按权值升序排序（求最小生成树）
    bool operator<(const Edge& rhs) const {
        return w < rhs.w;
    }
};

// Kruskal算法求解最小生成树
// 参数：n-节点数，edges-所有边的集合
// 返回值：pair<是否存在MST, MST的总权值>
pair<bool, ll> kruskal(int n, vector<Edge>& edges) {
    // 1. 按边权升序排序（核心步骤）
    sort(edges.begin(), edges.end());

    // 2. 初始化并查集
    DSU dsu(n);

    ll mst_sum = 0; // MST的总权值
    int edge_cnt = 0; // 已选入MST的边数

    // 3. 遍历所有边，贪心选边
    for (const Edge& e : edges) {
        int u = e.u, v = e.v;
        ll w = e.w;

        // 若u和v不连通，则选这条边加入MST
        if (dsu.unite(u, v)) {
            mst_sum += w;
            edge_cnt++;
            // 提前终止：MST需要n-1条边
            if (edge_cnt == n - 1) break;
        }
    }

    // 4. 判断是否存在MST（所有节点连通，即选够n-1条边）
    bool has_mst = (edge_cnt == n - 1);
    return {has_mst, mst_sum};
}

// ====================== 扩展：求最大生成树 ======================
// 只需修改Edge的排序规则（降序）
struct MaxEdge {
    int u, v;
    ll w;
    bool operator<(const MaxEdge& rhs) const {
        return w > rhs.w; // 降序排序
    }
};

pair<bool, ll> kruskal_max(int n, vector<MaxEdge>& edges) {
    sort(edges.begin(), edges.end());
    DSU dsu(n);
    ll mst_sum = 0;
    int edge_cnt = 0;
    for (const MaxEdge& e : edges) {
        if (dsu.unite(e.u, e.v)) {
            mst_sum += e.w;
            edge_cnt++;
            if (edge_cnt == n - 1) break;
        }
    }
    return {edge_cnt == n - 1, mst_sum};
}


// 2. 拓扑排序（Kahn算法，返回拓扑序，空表示有环）
vector<int> topological_sort(int n, const vector<vector<int>>& adj) {
    vector<int> in_degree(n + 1, 0);
    FOR(u, 1, n) for (int v : adj[u]) in_degree[v]++;

    queue<int> q;
    FOR(u, 1, n) if (in_degree[u] == 0) q.push(u);

    vector<int> res;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        res.pb(u);
        for (int v : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) q.push(v);
        }
    }
    return res.size() == n ? res : vector<int>();
}

// ====================== 数论 ======================
// 1. 快速幂（含模）
ll quick_pow(ll a, ll b, ll mod = MOD) {
    ll res = 1;
    a %= mod;
    while (b) {
        if (b & 1) res = res * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return res;
}

// 2. 欧拉筛（线性筛素数）
vector<int> euler_sieve(int n) {
    vector<bool> is_prime(n + 1, true);
    vector<int> primes;
    is_prime[0] = is_prime[1] = false;
    FOR(i, 2, n) {
        if (is_prime[i]) primes.pb(i);
        for (int p : primes) {
            if (i * p > n) break;
            is_prime[i * p] = false;
            if (i % p == 0) break;
        }
    }
    return primes;
}

// 3. 扩展欧几里得（解ax + by = gcd(a,b)）
ll exgcd(ll a, ll b, ll& x, ll& y) {
    if (b == 0) {
        x = 1, y = 0;
        return a;
    }
    ll d = exgcd(b, a % b, y, x);
    y -= a / b * x;
    return d;
}

// ====================== 动态规划 ======================
// 1. 01背包（n件物品，容量m，v价值，w重量）
ll knapsack_01(int n, int m, vector<int>& v, vector<int>& w) {
    vector<ll> dp(m + 1, 0);
    FOR(i, 1, n) FORD(j, m, w[i]) 
        dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
    return dp[m];
}

// 2. 完全背包（物品可无限选）
ll knapsack_complete(int n, int m, vector<int>& v, vector<int>& w) {
    vector<ll> dp(m + 1, 0);
    FOR(i, 1, n) FOR(j, w[i], m) 
        dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
    return dp[m];
}

// ====================== 字符串 ======================
// KMP算法（模式匹配）
namespace KMP {
    vector<int> get_next(const string& pat) {
        int n = pat.size();
        vector<int> nxt(n, 0);
        int j = 0;
        FOR(i, 1, n - 1) {
            while (j > 0 && pat[i] != pat[j]) j = nxt[j - 1];
            if (pat[i] == pat[j]) j++;
            nxt[i] = j;
        }
        return nxt;
    }

    vector<int> match(const string& s, const string& pat) {
        vector<int> nxt = get_next(pat);
        vector<int> res;
        int j = 0;
        REP(i, s.size()) {
            while (j > 0 && s[i] != pat[j]) j = nxt[j - 1];
            if (s[i] == pat[j]) j++;
            if (j == pat.size()) {
                res.pb(i - j + 1);
                j = nxt[j - 1];
            }
        }
        return res;
    }
}


