#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int N = 1e5 + 10, M = 2 * N;
int n, ans=N;
int h[N], e[M], ne[M], idx, st[N];
void add(int a, int b)
{
    e[idx] = b, ne[idx] = h[a], h[a] = idx++;
}

int dfs(int u)
{
    st[u] = 1; // 防止重复遍历 
    int sum = 1, res = 0;
    for (int i = h[u]; i != -1; i = ne[i])
    {
        int j = e[i];
        if(!st[j])
        {
            int s = dfs(j);
            res = max(res, s); // 先在当前u的子树中求一个节点最大值 
            sum += s; // 表示u节点子树的节点的总和 
        }
    }
    res = max(res, n - sum); // 再在以u的父节点为子树的求一个节点最大值 
    ans = min(ans, res); // 求最大值的最小值 
    return sum;
}

int main()
{
    cin >> n;
    memset(h, -1, sizeof h);
    for (int i = 1, u, v; i < n; i ++)  
    {
        cin >> u >> v;
        add(u, v);
        add(v, u);
    }
    dfs(1);
    cout << ans << endl;
    return 0;
}
