## 3. 并查集（路径压缩+按秩合并）

```cpp
const int N = 1e5 + 10;
int parent[N]; // 父节点
int rank_[N]; // 秩（树的高度）

// 初始化
void init() {
    for (int i = 0; i < N; i++) {
        parent[i] = i;
        rank_[i] = 1;
    }
}

// 查找根节点（路径压缩）
int find(int x) {
    if (parent[x] != x) parent[x] = find(parent[x]);
    return parent[x];
}

// 合并（按秩合并）
void unite(int x, int y) {
    x = find(x), y = find(y);
    if (x == y) return;
    if (rank_[x] < rank_[y]) swap(x, y);
    parent[y] = x;
    if (rank_[x] == rank_[y]) rank_[x]++;
}
```

