## 4. 最短路径算法模板

### Dijkstra（正权图单源最短路径）

#### 算法描述：

1. 初始化 dist[1] = 0, 其余节点的 dist 值为无穷大。
2. 找出第一个未被标记的，dist[x] 最小的节点 x, 然后标记节点 x。
3. 扫描节点 x 的所有出边 (x, y, z)， 若 dist[y] > dist[x] + z， 则使用 dist[x] + z 更新 dist[y]。
4. 重复上述 2 ～ 3 两个步骤，直到所有的节点都被标记。

[AcWing 849. Dijkstra求最短路 I](https://www.acwing.com/problem/content/851/)

**例题代码**:

```cpp
// 稠密图这里使用邻接数组
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int N = 550;
int n, m;
int g[N][N], dist[N], st[N];

int dijkstra()
{
    // 时间复杂度为 O(n^2)
    memset(dist, 0x3f, sizeof dist);
    dist[1] = 0;

    for (int i = 1; i < n; i ++) // 重复 n - 1 次
    {
        int t = -1;
        for (int j = 1; j <= n; j ++) // 找到未标记节点中 dist 最小的 (瓶颈主要在这里，可使用二叉堆优化)
        {
            if(!st[j] && (t == -1 || dist[t] > dist[j])) t = j;
        }
        st[t] = 1;
        // 用全局最小值点 x 更新其他节点
        for (int j = 1; j <= n; j ++)
            dist[j] = min(dist[j], dist[t] + g[t][j]);
    }

    if(dist[n] == 0x3f3f3f3f) return -1;
    else return dist[n];
}


int main()
{
    cin >> n >> m;
    memset(g, 0x3f, sizeof g);
    for (int i = 1, u, v, w; i <= m; i ++)
    {
        cin >> u >> v >> w;
        g[u][v] = min(g[u][v], w);
    }
    cout << dijkstra();
    return 0;
}
```

```cpp
// 使用邻接表实现
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int N = 1e6 + 10;
typedef pair<int, int> pii;
int n, m; 
int e[N], ne[N], h[N], val[N], dist[N], st[N], idx;
void add(int a, int b, int w)
{
    e[++ idx] = b, val[idx] = w, ne[idx] = h[a], h[a] = idx;
}

int dijkstra()
{
    memset(dist, 0x3f, sizeof dist);
    dist[1] = 0;

    priority_queue<pii, vector<pii>, greater<pii>> q;
    q.push({0, 1});


    while(q.size())
    {
        pii t = q.top(); q.pop();

        int distance = t.first, ver = t.second;

        if(st[ver]) continue;
        st[ver] = 1;

        for (int i = h[ver]; i != -1; i = ne[i])
        {
            int j = e[i];
            if(dist[j] > dist[ver] + val[i])
            {
                dist[j] = dist[ver] + val[i];
                q.push({dist[j], j});
            }
        }
    }

    if(dist[n] == 0x3f3f3f3f) return -1;
    else return dist[n];
}

int main()
{
    memset(h, -1, sizeof h);
    cin >> n >> m;
    for (int i = 1, u, v, w; i <= m; i ++)
    {
        cin >> u >> v >> w;
        add(u, v, w);
    }
    cout << dijkstra();
    return 0;   
}
