**模板**:

```cpp
#include <vector>
#include <queue>
#include <cstring>
using namespace std;

typedef pair<int, int> PII; // 第一维距离，第二维节点
const int N = 1e5 + 10, INF = 0x3f3f3f3f;
vector<PII> adj[N];
int dist[N];
bool st[N]; // 标记是否确定最短距离

void dijkstra(int start) {
    memset(dist, 0x3f, sizeof dist);
    memset(st, false, sizeof st);
    priority_queue<PII, vector<PII>, greater<PII>> heap; // 小根堆
    dist[start] = 0;
    heap.push({0, start});

    while (!heap.empty()) {
        auto [d, u] = heap.top();
        heap.pop();
        if (st[u]) continue;
        st[u] = true;
        for (auto [v, w] : adj[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                heap.push({dist[v], v});
            }
        }
    }
}
