### Prim（堆优化，稠密图首选）

```cpp
#include <vector>
#include <queue>
#include <cstring>
using namespace std;

typedef pair<int, int> PII; // 第一维边权，第二维节点
const int N = 1e5 + 10, INF = 0x3f3f3f3f;
vector<PII> adj[N];
bool st[N]; // 标记是否已加入生成树
int n, m;

int prim() {
    memset(st, false, sizeof st);
    priority_queue<PII, vector<PII>, greater<PII>> heap;
    heap.push({0, 1}); // 从节点1开始（可修改起点）
    int res = 0, cnt = 0;

    while (!heap.empty()) {
        auto [w, u] = heap.top();
        heap.pop();
        if (st[u]) continue;
        st[u] = true;
        res += w;
        cnt++;
        for (auto [v, ww] : adj[u]) {
            if (!st[v]) heap.push({ww, v});
        }
    }
    return cnt == n ? res : -1; // 不连通返回-1
}
