## 6. 强连通分量（Tarjan算法+缩点）

```cpp
#include <vector>
#include <stack>
#include <cstring>
using namespace std;

const int N = 1e5 + 10;
vector<int> adj[N];
int dfn[N], low[N], timestamp; // dfn时间戳，low能到达的最早时间戳
bool in_stack[N]; // 标记是否在栈中
stack<int> stk;
int scc_cnt; // 强连通分量数量
int id[N]; // 每个节点所属的强连通分量编号
int n, m;

void tarjan(int u) {
    dfn[u] = low[u] = ++timestamp;
    stk.push(u);
    in_stack[u] = true;
    for (int v : adj[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]);
        } else if (in_stack[v]) {
            low[u] = min(low[u], dfn[v]);
        }
    }
    // 找到强连通分量的根
    if (dfn[u] == low[u]) {
        scc_cnt++;
        int v;
        do {
            v = stk.top();
            stk.pop();
            in_stack[v] = false;
            id[v] = scc_cnt;
        } while (v != u);
    }
}

// 缩点：构建新的DAG
vector<int> new_adj[N];
int scc_size[N]; // 每个强连通分量的大小

void shrink() {
    memset(dfn, 0, sizeof dfn);
    memset(low, 0, sizeof low);
    memset(in_stack, false, sizeof in_stack);
    timestamp = scc_cnt = 0;
    for (int i = 1; i <= n; i++) {
        if (!dfn[i]) tarjan(i);
    }
    // 统计每个SCC大小
    for (int i = 1; i <= n; i++) scc_size[id[i]]++;
    // 建DAG
    for (int u = 1; u <= n; u++) {
        for (int v : adj[u]) {
            if (id[u] != id[v]) {
                new_adj[id[u]].push_back(id[v]);
            }
        }
    }
}
