```cpp
#include <vector>
#include <cstring>
using namespace std;

const int N = 1e3 + 10, M = 1e5 + 10;
vector<int> adj[N]; // 左部节点→右部节点
int match[M]; // 右部节点匹配的左部节点
bool st[M]; // 标记右部节点是否被访问
int n1, n2; // 左部节点数、右部节点数

// 尝试给左部节点u找匹配
bool find(int u) {
    for (int v : adj[u]) {
        if (!st[v]) {
            st[v] = true;
            if (match[v] == 0 || find(match[v])) {
                match[v] = u;
                return true;
            }
        }
    }
    return false;
}

// 求最大匹配数
int hungarian() {
    memset(match, 0, sizeof match);
    int res = 0;
    for (int u = 1; u <= n1; u++) {
        memset(st, false, sizeof st);
        if (find(u)) res++;
    }
    return res;
}
