## 8. 拓扑排序（Kahn算法）

```cpp
#include <vector>
#include <queue>
#include <cstring>
using namespace std;

const int N = 1e5 + 10;
vector<int> adj[N];
int in_degree[N]; // 入度
int topo[N]; // 存储拓扑序列
int n, m;

// 返回拓扑序列长度，0表示有环
int kahn() {
    queue<int> q;
    int cnt = 0; // 拓扑序列长度
    // 入度为0的节点入队
    for (int i = 1; i <= n; i++) {
        if (in_degree[i] == 0) q.push(i);
    }
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topo[cnt++] = u;
        for (int v : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) q.push(v);
        }
    }
    return cnt == n ? cnt : 0;
}
